queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?dissertations a :Dissertations .
    ?dissertations p:Title ?title .
    ?dissertations p:Academic_Supervisor ?academic_supervisor_f .
    FILTER(STR(?academic_supervisor_f) = "Dr. Jane Smith")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?thesis_proposals a :Thesis_Proposals .
    ?thesis_proposals p:Title ?title .
    ?thesis_proposals p:Academic_Supervisor ?academic_supervisor_f .
    FILTER(STR(?academic_supervisor_f) = "Dr. Jane Smith")
    BIND(?title AS ?o0)
  }
}

